import{overlayModalMsgs,adicionarEventoPageshow,alternarVisibilidade,adicionarEventoLoad,enviarDados,exibirErrConsole,alternarModalMsgs,adicionarEventoKeydown,adicionarEventoClick,}from "./utils.min.js";const botaoAbrirSidebar=document.querySelector("#botaoAbrirSidebar");const overlaySidebar=document.querySelector("#overlaySidebar");const sidebar=document.querySelector("#sidebar");const botaoFecharSidebar=document.querySelector("#botaoFecharSidebar");const botaoFecharModalMsgs=document.querySelector("#botaoFecharModalMsgs");const copyright=document.querySelector("#copyright");const alternarSidebar=(exibir)=>{alternarVisibilidade([overlaySidebar,sidebar],exibir)};adicionarEventoPageshow((e)=>{if(e.persisted){window.location.reload()}});adicionarEventoPageshow(()=>{alternarSidebar(!1)});adicionarEventoLoad(async()=>{const params={acao:"consultar_ano_atual"};const url="consultar_ano_atual.php";const metodo="GET";const{sucesso,dados,msg}=await enviarDados(params,url,metodo);if(sucesso){const{anoAtual}=dados;const elAnoAtual=copyright.querySelector("span");elAnoAtual.textContent=anoAtual;return}
exibirErrConsole(msg)});adicionarEventoLoad(()=>{const msg=localStorage.getItem("msg");if(msg){alternarModalMsgs(!0,msg);localStorage.removeItem("msg")}});adicionarEventoKeydown(document,(e)=>{if(e.key==="Escape"){alternarSidebar(!1);alternarModalMsgs(!1)}});adicionarEventoClick([botaoAbrirSidebar],()=>{alternarSidebar(!0)});adicionarEventoClick([overlaySidebar,botaoFecharSidebar],()=>{alternarSidebar(!1)});adicionarEventoClick([overlayModalMsgs,botaoFecharModalMsgs],()=>{alternarModalMsgs(!1)});window.addEventListener("resize",()=>{if(window.innerWidth>=768){alternarSidebar(!1)}})